"use client";

import { useState, useEffect, useMemo, useRef } from "react";
import {
  motion,
  useMotionValue,
  useSpring,
  useTransform,
  AnimatePresence,
} from "framer-motion";
import type { AgentRole } from "@/lib/types";
import { AGENT_ROLES } from "@/lib/types";
import { getAgentVisual, hexToRgb } from "@/lib/agent-visuals";

// ΓöÇΓöÇΓöÇ Agent display helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function getTokenMeta(role: string) {
  const v = getAgentVisual(role);
  return {
    label: v.tag,
    color: v.hex,
    glow: `rgba(${hexToRgb(v.hex)}, 0.45)`,
    gradient: `linear-gradient(90deg, ${v.hex} 0%, ${v.gradientEnd} 100%)`,
  };
}

const AGENT_ORDER: string[] = [
  AGENT_ROLES.RESEARCHER,
  AGENT_ROLES.EXPLORER,
  AGENT_ROLES.ANALYST,
  AGENT_ROLES.ANALYST_UI,
  AGENT_ROLES.ANALYST_BACKEND,
  AGENT_ROLES.ANALYST_DATABASE,
  AGENT_ROLES.ANALYST_DOCS,
  AGENT_ROLES.FIXER,
  AGENT_ROLES.FIXER_UI,
  AGENT_ROLES.FIXER_BACKEND,
  AGENT_ROLES.FIXER_DATABASE,
  AGENT_ROLES.FIXER_DOCS,
  AGENT_ROLES.CONSOLIDATOR,
  AGENT_ROLES.UX_REVIEWER,
  AGENT_ROLES.CODE_SIMPLIFIER,
];

// Pipeline phases for tab-based navigation
const PHASES = [
  { id: "all", label: "All", roles: null },
  { id: "research", label: "Research", roles: [AGENT_ROLES.RESEARCHER] },
  { id: "explore", label: "Explore", roles: [AGENT_ROLES.EXPLORER] },
  { id: "analyze", label: "Analyze", roles: [AGENT_ROLES.ANALYST, AGENT_ROLES.ANALYST_UI, AGENT_ROLES.ANALYST_BACKEND, AGENT_ROLES.ANALYST_DATABASE, AGENT_ROLES.ANALYST_DOCS] },
  { id: "fix", label: "Fix", roles: [AGENT_ROLES.FIXER, AGENT_ROLES.FIXER_UI, AGENT_ROLES.FIXER_BACKEND, AGENT_ROLES.FIXER_DATABASE, AGENT_ROLES.FIXER_DOCS] },
  { id: "merge", label: "Merge", roles: [AGENT_ROLES.CONSOLIDATOR] },
  { id: "simplify", label: "Simplify", roles: [AGENT_ROLES.CODE_SIMPLIFIER] },
  { id: "ux", label: "UX", roles: [AGENT_ROLES.UX_REVIEWER] },
] as const;

// In "All" view, domain agents are rolled up into their parent role
const ROLLUP_GROUPS: Record<string, string[]> = {
  [AGENT_ROLES.ANALYST]: [AGENT_ROLES.ANALYST, AGENT_ROLES.ANALYST_UI, AGENT_ROLES.ANALYST_BACKEND, AGENT_ROLES.ANALYST_DATABASE, AGENT_ROLES.ANALYST_DOCS],
  [AGENT_ROLES.FIXER]: [AGENT_ROLES.FIXER, AGENT_ROLES.FIXER_UI, AGENT_ROLES.FIXER_BACKEND, AGENT_ROLES.FIXER_DATABASE, AGENT_ROLES.FIXER_DOCS],
};

// Roles shown in "All" view (domain variants rolled into parent)
const ALL_VIEW_ROLES: string[] = [
  AGENT_ROLES.RESEARCHER,
  AGENT_ROLES.EXPLORER,
  AGENT_ROLES.ANALYST,
  AGENT_ROLES.FIXER,
  AGENT_ROLES.CONSOLIDATOR,
  AGENT_ROLES.CODE_SIMPLIFIER,
  AGENT_ROLES.UX_REVIEWER,
];

// ΓöÇΓöÇΓöÇ Full metrics shape ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface FullMetrics {
  agentInputTokens?: Record<string, number>;
  agentOutputTokens?: Record<string, number>;
  agentCacheReadTokens?: Record<string, number>;
  agentCacheWriteTokens?: Record<string, number>;
  agentTurns?: Record<string, number>;
  toolInvocations?: Record<string, number>;
  buildsPass?: number;
  buildsFail?: number;
  cyclesCompleted?: number;
  compactions?: number;
  contextUsage?: number;
  contextTokenLimit?: number;
  contextCurrentTokens?: number;
  tasksCreated?: number;
  tasksResolved?: number;
  uxScores?: Record<string, number>;
  modelMaxContextTokens?: number;
  totalPremiumRequests?: number;
  totalCodeChanges?: { linesAdded: number; linesRemoved: number; filesModified: number };
}

// ΓöÇΓöÇΓöÇ Format helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function formatTokens(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return String(n);
}

// ΓöÇΓöÇΓöÇ Animated number with spring physics ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function SpringNumber({
  value,
  color,
  className = "font-mono text-xs font-bold tabular-nums",
}: {
  value: number;
  color: string;
  className?: string;
}) {
  const motionVal = useMotionValue(0);
  const spring = useSpring(motionVal, { stiffness: 60, damping: 18 });
  const display = useTransform(spring, (v) => formatTokens(Math.round(v)));
  const [text, setText] = useState(formatTokens(0));

  useEffect(() => {
    motionVal.set(value);
  }, [value]); // eslint-disable-line react-hooks/exhaustive-deps -- motionVal is a stable MotionValue ref

  useEffect(() => {
    return display.on("change", (v) => setText(v));
  }, []); // eslint-disable-line react-hooks/exhaustive-deps -- display is a stable MotionValue ref

  return (
    <span className={className} style={{ color }}>
      {text}
    </span>
  );
}

function SpringInt({
  value,
  color,
  className = "font-mono text-sm font-bold tabular-nums",
}: {
  value: number;
  color: string;
  className?: string;
}) {
  const motionVal = useMotionValue(0);
  const spring = useSpring(motionVal, { stiffness: 100, damping: 20 });
  const [display, setDisplay] = useState(0);

  useEffect(() => {
    motionVal.set(value);
  }, [value]); // eslint-disable-line react-hooks/exhaustive-deps -- motionVal is a stable MotionValue ref

  useEffect(() => {
    return spring.on("change", (v: number) => setDisplay(Math.round(v)));
  }, []); // eslint-disable-line react-hooks/exhaustive-deps -- spring is a stable MotionValue ref

  return (
    <span className={className} style={{ color }}>
      {display}
    </span>
  );
}

// ΓöÇΓöÇΓöÇ Single Agent Bar ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface AgentBarProps {
  role: string;
  inputTokens: number;
  outputTokens: number;
  maxTokens: number;
  isActive: boolean;
  prevTotal: number;
  isCompacting: boolean;
}

function AgentBar({
  role,
  inputTokens,
  outputTokens,
  maxTokens,
  isActive,
  prevTotal,
  isCompacting,
}: AgentBarProps) {
  const meta = getTokenMeta(role);

  const total = inputTokens + outputTokens;
  const inputPct = maxTokens > 0 ? (inputTokens / maxTokens) * 100 : 0;
  const outputPct = maxTokens > 0 ? (outputTokens / maxTokens) * 100 : 0;
  const isGrowing = total > prevTotal;

  return (
    <div className="flex flex-1 flex-col gap-1.5 min-w-0">
      {/* Label row */}
      <div className="flex items-center justify-between gap-2">
        <div className="flex items-center gap-1.5">
          <motion.div
            className="h-2 w-2 rounded-full shrink-0"
            style={{ backgroundColor: meta.color }}
            animate={
              isActive
                ? {
                    scale: [1, 1.6, 1],
                    boxShadow: [
                      `0 0 0px ${meta.glow}`,
                      `0 0 12px ${meta.glow}`,
                      `0 0 0px ${meta.glow}`,
                    ],
                  }
                : { scale: 1, boxShadow: `0 0 0px ${meta.glow}` }
            }
            transition={
              isActive
                ? { duration: 1.4, repeat: Infinity, ease: "easeInOut" }
                : { duration: 0.3 }
            }
          />
          <span
            className="text-[10px] font-semibold uppercase tracking-widest"
            style={{ color: isActive ? meta.color : "var(--color-text-muted)" }}
          >
            {meta.label}
          </span>
        </div>

        <div className="flex items-center gap-1.5">
          <span className="text-[8px] text-text-muted/50 hidden sm:inline">
            {total > 0
              ? `${formatTokens(inputTokens)} in ┬╖ ${formatTokens(outputTokens)} out`
              : ""}
          </span>
          <SpringNumber value={total} color={total > 0 ? meta.color : "var(--color-text-muted)"} />
        </div>
      </div>

      {/* Bar track */}
      <div className="relative h-3 w-full overflow-hidden rounded-full bg-white/[0.03]">
        <div
          className="absolute inset-0 opacity-[0.03]"
          style={{
            backgroundImage:
              "repeating-linear-gradient(90deg, transparent, transparent 4px, rgba(255,255,255,0.15) 4px, rgba(255,255,255,0.15) 5px)",
          }}
        />

        {/* Input segment */}
        <motion.div
          className="absolute inset-y-0 left-0 rounded-full"
          style={{ background: meta.gradient, opacity: 0.9 }}
          initial={{ width: 0 }}
          animate={{ width: `${inputPct}%` }}
          transition={{ type: "spring", stiffness: 120, damping: 20 }}
        />

        {/* Output segment */}
        <motion.div
          className="absolute inset-y-0 rounded-full"
          style={{
            left: `${inputPct}%`,
            background: meta.gradient,
            opacity: 0.5,
          }}
          initial={{ width: 0 }}
          animate={{ width: `${outputPct}%` }}
          transition={{ type: "spring", stiffness: 120, damping: 20 }}
        />

        {/* Throbbing glow overlay when actively growing */}
        <AnimatePresence>
          {isGrowing && (
            <motion.div
              className="absolute inset-0 rounded-full"
              style={{
                background: `linear-gradient(90deg, transparent 0%, ${meta.color}20 50%, transparent 100%)`,
                backgroundSize: "200% 100%",
              }}
              initial={{ opacity: 0 }}
              animate={{
                opacity: [0, 0.6, 0],
                backgroundPosition: ["-100% 0%", "200% 0%"],
              }}
              exit={{ opacity: 0 }}
              transition={{
                duration: 2,
                repeat: Infinity,
                ease: "easeInOut",
              }}
            />
          )}
        </AnimatePresence>

        {/* Compaction: dramatic scan line when context is being compressed */}
        <AnimatePresence>
          {isCompacting && isActive && (
            <motion.div
              className="absolute inset-y-0 w-full rounded-full"
              style={{
                background: `linear-gradient(90deg, transparent 0%, rgba(0, 229, 255, 0.4) 50%, transparent 100%)`,
                backgroundSize: "40% 100%",
              }}
              initial={{ backgroundPosition: "-40% 0%", opacity: 0 }}
              animate={{
                backgroundPosition: ["0% 0%", "140% 0%"],
                opacity: [0, 1, 0],
              }}
              exit={{ opacity: 0 }}
              transition={{
                duration: 1.2,
                repeat: Infinity,
                ease: "easeInOut",
              }}
            />
          )}
        </AnimatePresence>

        {/* Active agent: pulsing edge glow */}
        {isActive && total > 0 && (
          <motion.div
            className="absolute inset-y-0 w-1 rounded-full"
            style={{
              left: `${Math.min(inputPct + outputPct, 100)}%`,
              background: meta.color,
              boxShadow: `0 0 8px ${meta.glow}, 0 0 20px ${meta.glow}`,
            }}
            animate={{
              opacity: [0.4, 1, 0.4],
              scaleY: [0.7, 1.1, 0.7],
            }}
            transition={{
              duration: 1.2,
              repeat: Infinity,
              ease: "easeInOut",
            }}
          />
        )}
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Stat Pill ΓÇö small animated metric chip ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function StatPill({
