// ΓöÇΓöÇΓöÇ Agent Leaderboard mini ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function AgentLeaderboard({ turns }: { turns: Record<string, number> }) {
  const sorted = useMemo(() => {
    return AGENT_ORDER
      .map((role) => ({ role, turns: turns[role] ?? 0 }))
      .filter((s) => s.turns > 0)
      .sort((a, b) => b.turns - a.turns);
  }, [turns]);

  const maxTurns = Math.max(...sorted.map((s) => s.turns), 1);

  if (sorted.length === 0) return null;

  return (
    <div className="flex flex-col gap-1 min-w-[80px]">
      <span className="text-[8px] uppercase tracking-[0.15em] text-text-muted text-center mb-0.5">
        Agent Turns
      </span>
      {sorted.map(({ role, turns: t }, i) => {
        const meta = getTokenMeta(role);
        const pct = maxTurns > 0 ? (t / maxTurns) * 100 : 0;

        return (
          <div key={role} className="flex items-center gap-1.5">
            {/* Rank medal for top agent */}
            <span className="text-[9px] w-3 text-center shrink-0">
              {i === 0 && t > 0 ? "≡ƒææ" : ""}
            </span>
            <div
              className="h-1 rounded-full flex-1 overflow-hidden"
              style={{ background: "rgba(255,255,255,0.03)" }}
            >
              <motion.div
                className="h-full rounded-full"
                style={{ background: meta.color, opacity: 0.7 }}
                initial={{ width: 0 }}
                animate={{ width: `${pct}%` }}
                transition={{ type: "spring", stiffness: 120, damping: 20 }}
              />
            </div>
            <span
              className="font-mono text-[9px] font-bold tabular-nums w-5 text-right shrink-0"
              style={{ color: meta.color }}
            >
              {t}
            </span>
          </div>
        );
      })}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Main Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface TokenUsageDisplayProps {
  activeAgent: AgentRole | null;
  isCompacting: boolean;
}

export function TokenUsageDisplay({
  activeAgent,
  isCompacting,
}: TokenUsageDisplayProps) {
  const [metrics, setMetrics] = useState<FullMetrics>({});
  const [activePhase, setActivePhase] = useState("all");
  const [prevTotals, setPrevTotals] = useState<Record<string, number>>({});
  const [prevMetrics, setPrevMetrics] = useState<{
    buildsPass: number;
    buildsFail: number;
    toolCalls: number;
    tasksResolved: number;
    compactions: number;
  }>({ buildsPass: 0, buildsFail: 0, toolCalls: 0, tasksResolved: 0, compactions: 0 });

  // Track compaction flash timing ΓÇö show a dramatic flash when compaction just ended
  const [justCompacted, setJustCompacted] = useState(false);
  const compactTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const prevCompacting = useRef(false);

  useEffect(() => {
    // Detect transition from compacting ΓåÆ not compacting
    if (prevCompacting.current && !isCompacting) {
      setJustCompacted(true);
      compactTimerRef.current = setTimeout(() => setJustCompacted(false), 2000);
    }
    prevCompacting.current = isCompacting;
    return () => {
      if (compactTimerRef.current) clearTimeout(compactTimerRef.current);
    };
  }, [isCompacting]);

  // Use a ref to track previous metrics for snapshot diffs
  const metricsRef = useRef<FullMetrics>({});

  // Poll metrics ΓÇö 3s for responsive updates
  useEffect(() => {
    let cancelled = false;
    const fetchMetrics = () => {
      fetch("/api/metrics")
        .then((r) => r.json())
        .then((data: { metrics?: FullMetrics }) => {
          if (cancelled || !data.metrics) return;

          // Snapshot previous values from ref (not inside setState)
          const prev = metricsRef.current;
          const inp = prev.agentInputTokens ?? {};
          const out = prev.agentOutputTokens ?? {};
          const totals: Record<string, number> = {};
          for (const role of AGENT_ORDER) {
            totals[role] = (inp[role] ?? 0) + (out[role] ?? 0);
          }
          setPrevTotals(totals);

          const prevToolCalls = prev.toolInvocations
            ? Object.values(prev.toolInvocations).reduce((s, v) => s + v, 0)
            : 0;
          setPrevMetrics({
            buildsPass: prev.buildsPass ?? 0,
            buildsFail: prev.buildsFail ?? 0,
            toolCalls: prevToolCalls,
            tasksResolved: prev.tasksResolved ?? 0,
            compactions: prev.compactions ?? 0,
          });

          // Now update the metrics state and ref
          metricsRef.current = data.metrics;
          setMetrics(data.metrics);
        })
        .catch(() => {});
    };

    fetchMetrics();
    const interval = setInterval(fetchMetrics, 3_000);
    return () => { cancelled = true; clearInterval(interval); };
  }, []);

  const totalTokens = useMemo(() => {
    const inp = metrics.agentInputTokens ?? {};
    const out = metrics.agentOutputTokens ?? {};
    const allRoles = new Set([...Object.keys(inp), ...Object.keys(out)]);
    let sum = 0;
    for (const r of allRoles) sum += (inp[r] ?? 0) + (out[r] ?? 0);
    return sum;
  }, [metrics.agentInputTokens, metrics.agentOutputTokens]);

  // Scale bars against the model's actual context window from SDK metadata.
  // Prefer SDK-native context window data (session.usage_info) when available.
  // Falls back to model metadata, then to estimation.
  const sdkTokenLimit = metrics.contextTokenLimit ?? 0;
  const sdkCurrentTokens = metrics.contextCurrentTokens ?? 0;
  const modelMax = metrics.modelMaxContextTokens ?? 0;
  const agentMax = useMemo(() => {
    // Tier 1: SDK session.usage_info provides exact token limit
    if (sdkTokenLimit > 0) return sdkTokenLimit;
    // Tier 2: Model metadata provides max context window
    if (modelMax > 0) return modelMax;
    // Tier 3: Fallback estimation from observed usage
    const inp = metrics.agentInputTokens ?? {};
    const out = metrics.agentOutputTokens ?? {};
    let maxSingle = 0;
    for (const role of AGENT_ORDER) {
      const t = (inp[role] ?? 0) + (out[role] ?? 0);
      if (t > maxSingle) maxSingle = t;
    }
    return Math.max(maxSingle * 1.5, 200_000);
  }, [metrics.agentInputTokens, metrics.agentOutputTokens, modelMax, sdkTokenLimit]);

  const totalToolCalls = useMemo(() => {
    if (!metrics.toolInvocations) return 0;
    return Object.values(metrics.toolInvocations).reduce((s, v) => s + v, 0);
  }, [metrics.toolInvocations]);

  const hasAnyActivity =
    totalTokens > 0 ||
    (metrics.buildsPass ?? 0) + (metrics.buildsFail ?? 0) > 0 ||
    totalToolCalls > 0;

  return (
    <motion.div
      initial={{ opacity: 0, height: 0 }}
      animate={{ opacity: 1, height: "auto" }}
      transition={{ type: "spring", stiffness: 300, damping: 30 }}
      className="glass-panel relative shrink-0 border-t-0 overflow-hidden"
    >
      {/* Ambient background gradient */}
      {hasAnyActivity && (
        <motion.div
          className="pointer-events-none absolute inset-0"
          style={{
            background:
              "linear-gradient(90deg, rgba(0,229,255,0.02) 0%, rgba(176,38,255,0.02) 33%, rgba(0,255,163,0.02) 66%, rgba(255,184,0,0.02) 100%)",
          }}
          animate={{ opacity: [0.3, 0.7, 0.3] }}
          transition={{ duration: 6, repeat: Infinity, ease: "easeInOut" }}
        />
      )}

      {/* Compaction flash ΓÇö dramatic white-out sweep across entire strip */}
      <AnimatePresence>
        {justCompacted && (
          <motion.div
            className="pointer-events-none absolute inset-0 z-20"
            style={{
              background:
                "linear-gradient(90deg, transparent, rgba(0, 229, 255, 0.15), rgba(255, 255, 255, 0.08), rgba(0, 229, 255, 0.15), transparent)",
              backgroundSize: "40% 100%",
            }}
            initial={{ backgroundPosition: "-40% 0%", opacity: 0 }}
            animate={{
              backgroundPosition: ["-40% 0%", "140% 0%"],
              opacity: [0, 1, 0],
            }}
            exit={{ opacity: 0 }}
            transition={{ duration: 1.5, ease: "easeOut" }}
          />
        )}
      </AnimatePresence>

      <div className="relative flex items-center gap-4 px-4 py-2.5">
        {/* ΓöÇΓöÇ Token Section with Phase Tabs ΓöÇΓöÇ */}
        <div className="flex flex-col gap-1.5 flex-1 min-w-0 overflow-hidden">
          {/* Phase tabs */}
          <div className="flex items-center gap-1">
            {PHASES.filter((phase) => {
              // Only show a phase tab if it has activity or is "all"
              if (!phase.roles) return true;
              return phase.roles.some((r) => {
                const inp = metrics.agentInputTokens?.[r] ?? 0;
                const out = metrics.agentOutputTokens?.[r] ?? 0;
                return inp + out > 0;
              });
            }).map((phase) => {
              const isActive = activePhase === phase.id;
              // Get phase color from the first role's visuals
              const phaseColor = phase.roles ? getTokenMeta(phase.roles[0]).color : "#00E5FF";
              return (
                <button
                  key={phase.id}
                  onClick={() => setActivePhase(phase.id)}
                  className="rounded px-2 py-0.5 text-[8px] font-semibold uppercase tracking-widest transition-colors"
                  style={{
                    color: isActive ? phaseColor : "var(--color-text-muted)",
                    background: isActive ? `${phaseColor}15` : "transparent",
                    borderBottom: isActive ? `1px solid ${phaseColor}` : "1px solid transparent",
                  }}
                >
                  {phase.label}
                </button>
              );
            })}
          </div>

          {/* Agent bars */}
          <div className="flex flex-1 items-stretch gap-3 min-w-0 overflow-x-auto">
            {(() => {
              const phase = PHASES.find((p) => p.id === activePhase);
              const inp = metrics.agentInputTokens ?? {};
              const out = metrics.agentOutputTokens ?? {};

              if (activePhase === "all") {
                // Rolled-up view: show parent roles with summed tokens from children
                return ALL_VIEW_ROLES.filter((role) => {
                  const group = ROLLUP_GROUPS[role];
                  if (group) {
                    return group.some((r) => (inp[r] ?? 0) + (out[r] ?? 0) > 0);
                  }
                  return (inp[role] ?? 0) + (out[role] ?? 0) > 0 || activeAgent === role;
                }).map((role) => {
                  const group = ROLLUP_GROUPS[role];
                  let inputTokens = inp[role] ?? 0;
                  let outputTokens = out[role] ?? 0;
                  let prevTotal = prevTotals[role] ?? 0;
                  const isGroupActive = group
                    ? group.some((r) => activeAgent === r)
                    : activeAgent === role;

                  if (group) {
                    inputTokens = group.reduce((s, r) => s + (inp[r] ?? 0), 0);
                    outputTokens = group.reduce((s, r) => s + (out[r] ?? 0), 0);
                    prevTotal = group.reduce((s, r) => s + (prevTotals[r] ?? 0), 0);
                  }

                  return (
                    <AgentBar
                      key={role}
                      role={role}
                      inputTokens={inputTokens}
                      outputTokens={outputTokens}
                      maxTokens={agentMax}
                      isActive={isGroupActive}
                      prevTotal={prevTotal}
                      isCompacting={isCompacting}
                    />
                  );
                });
              }

              // Phase-specific view: show individual agents in this phase
              const roles = phase?.roles ?? AGENT_ORDER;
              return roles.filter((role) => {
                return (inp[role] ?? 0) + (out[role] ?? 0) > 0 || activeAgent === role;
              }).map((role) => (
                <AgentBar
                  key={role}
                  role={role}
                  inputTokens={inp[role] ?? 0}
                  outputTokens={out[role] ?? 0}
                  maxTokens={agentMax}
                  isActive={activeAgent === role}
                  prevTotal={prevTotals[role] ?? 0}
                  isCompacting={isCompacting}
                />
              ));
            })()}
            {/* Empty state when no agents have activity */}
            {!hasAnyActivity && (
              <div className="flex items-center gap-2 py-1 text-text-muted/50">
                <span className="text-[10px] uppercase tracking-widest">No agent activity yet</span>
              </div>
            )}
          </div>
        </div>

        {/* Total tokens badge */}
        <div className="flex flex-col items-center gap-0.5 shrink-0">
          <SpringNumber
            value={totalTokens}
            color={totalTokens > 0 ? "#00E5FF" : "var(--color-text-muted)"}
            className="font-mono text-sm font-bold tabular-nums"
          />
          <span className="text-[7px] uppercase tracking-[0.15em] text-text-muted">
            Tokens
          </span>
        </div>

        {/* ΓöÇΓöÇ Divider ΓöÇΓöÇ */}
        <div className="h-10 w-px shrink-0 bg-white/[0.06]" />

        {/* ΓöÇΓöÇ Gamification Stats ΓöÇΓöÇ */}
        <div className="flex items-center gap-3 shrink-0">
          {/* Build streak */}
          <BuildStreakBar
            pass={metrics.buildsPass ?? 0}
            fail={metrics.buildsFail ?? 0}
            prevPass={prevMetrics.buildsPass}
          />

          {/* Stat pills */}
          <StatPill
            icon={
              <svg className="h-2.5 w-2.5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round">
                <path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z" />
              </svg>
            }
            label="Tools"
            value={totalToolCalls}
            color="#B026FF"
            glowColor="rgba(176, 38, 255, 0.3)"
            prevValue={prevMetrics.toolCalls}
          />

          <StatPill
            icon={
              <svg className="h-2.5 w-2.5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round">
                <polyline points="20 6 9 17 4 12" />
              </svg>
            }
            label="Resolved"
            value={metrics.tasksResolved ?? 0}
            color="#00FFA3"
            glowColor="rgba(0, 255, 163, 0.3)"
            prevValue={prevMetrics.tasksResolved}
          />

          {/* Compaction indicator */}
          <CompactionIndicator
            count={metrics.compactions ?? 0}
            isCompacting={isCompacting}
          />

          {/* Agent leaderboard */}
          <AgentLeaderboard turns={metrics.agentTurns ?? {}} />
        </div>
      </div>
    </motion.div>
  );
}

"use client";

import { useMemo, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { AgentRole, PipelineStatus, AgentGraphNode, Domain } from "@/lib/types";
import { AGENT_ROLES, DOMAINS, PIPELINE_STATUSES, GRAPH_NODE_TYPES, DEFAULT_AGENT_GRAPH, getDomainFromRole } from "@/lib/types";
import { getAgentVisual } from "@/lib/agent-visuals";

// ΓöÇΓöÇΓöÇ Constants ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const DOMAIN_LABELS: Record<string, string> = {
  [DOMAINS.UI]: "UI",
  [DOMAINS.BACKEND]: "Backend",
  [DOMAINS.DATABASE]: "Database",
  [DOMAINS.DOCS]: "Docs",
};

// Domain colors are centralized in globals.css as --color-domain-* vars.
// These hex values must match for SVG rendering (SVG can't resolve CSS vars).
// Source of truth: globals.css ΓåÆ --color-domain-*
const DOMAIN_COLORS: Record<string, string> = {
  [DOMAINS.UI]: "#00E5FF",
  [DOMAINS.BACKEND]: "#B026FF",
  [DOMAINS.DATABASE]: "#FFD700",
  [DOMAINS.DOCS]: "#FF69B4",
};

const NODE_RADIUS = 20;
const LAYER_GAP = 72;
const DOMAIN_SPREAD = 110;
const PADDING_Y = 40;
const PADDING_X = 60;

const BREATHE_TRANSITION = {
  duration: 2,
  repeat: Infinity,
  repeatType: "reverse" as const,
  ease: "easeInOut" as const,
};

const SPRING = { type: "spring" as const, stiffness: 200, damping: 20 };

// Cycle arc colors ΓÇö clockwise flow
const LOOP_COLOR_RIGHT = "#A855F7"; // violet ΓÇö Explorer ΓåÆ UX (down the right)
const LOOP_COLOR_LEFT = "#6366F1";  // indigo ΓÇö UX ΓåÆ Explorer (up the left)
const LOOP_MARGIN = 140; // Must be large ΓÇö cubic bezier peaks at ~75% of control point distance from center

// ΓöÇΓöÇΓöÇ Layout computation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface LayoutNode {
  role: AgentRole;
  x: number;
  y: number;
  color: string;
  label: string;
  icon: string;
  description: string;
  nodeType: string;
  parallel: boolean;
  domain?: Domain;
  dynamicEnable?: boolean;
}

interface LayoutEdge {
  from: LayoutNode;
  to: LayoutNode;
}

/**
 * Compute a vertical DAG layout.
 * Nodes are arranged top-to-bottom by topological depth.
 * Parallel siblings at the same depth are fanned out horizontally.
 */
function computeLayout(graph: AgentGraphNode[]): {
  nodes: LayoutNode[];
  edges: LayoutEdge[];
  width: number;
  height: number;
} {
  if (graph.length === 0) return { nodes: [], edges: [], width: 400, height: 200 };

  // Compute topological depth
  const depth: Record<string, number> = {};
  function computeDepth(role: string): number {
    if (depth[role] !== undefined) return depth[role];
    const node = graph.find((n) => n.role === role);
    if (!node || node.runAfter.length === 0) {
      depth[role] = 0;
      return 0;
    }
    const maxParent = Math.max(...node.runAfter.map((dep) => computeDepth(dep)));
    depth[role] = maxParent + 1;
    return depth[role];
  }
  for (const node of graph) computeDepth(node.role);

  // Group by depth into layers
  const layers: AgentGraphNode[][] = [];
  for (const node of graph) {
    const d = depth[node.role] ?? 0;
    if (!layers[d]) layers[d] = [];
    layers[d].push(node);
  }

  // Figure out max layer width for centering
  let maxLayerWidth = 0;
  for (const layer of layers) {
    if (!layer) continue;
    if (layer.length > 1) {
      maxLayerWidth = Math.max(maxLayerWidth, (layer.length - 1) * DOMAIN_SPREAD);
    }
  }

  const centerX = Math.max(PADDING_X + maxLayerWidth / 2, 200);

  // Compute positions
  const nodes: LayoutNode[] = [];
  let maxX = 0;

  for (let li = 0; li < layers.length; li++) {
    const layer = layers[li];
    if (!layer) continue;
    const y = PADDING_Y + li * LAYER_GAP;

    if (layer.length === 1) {
      const node = layer[0];
      const vis = getAgentVisual(node.role);
      nodes.push({
        role: node.role, x: centerX, y,
        color: vis.hex, label: vis.tag, icon: vis.icon,
        description: vis.description,
        nodeType: node.nodeType, parallel: node.parallel,
        domain: node.domain as Domain | undefined,
        dynamicEnable: node.dynamicEnable,
      });
      maxX = Math.max(maxX, centerX + PADDING_X);
    } else {
      const totalWidth = (layer.length - 1) * DOMAIN_SPREAD;
      const startX = centerX - totalWidth / 2;
      for (let ni = 0; ni < layer.length; ni++) {
        const node = layer[ni];
        const vis = getAgentVisual(node.role);
        const x = startX + ni * DOMAIN_SPREAD;
        nodes.push({
          role: node.role, x, y,
          color: vis.hex, label: vis.tag, icon: vis.icon,
          description: vis.description,
          nodeType: node.nodeType, parallel: node.parallel,
          domain: node.domain as Domain | undefined,
          dynamicEnable: node.dynamicEnable,
        });
        maxX = Math.max(maxX, x + PADDING_X);
      }
    }
  }

  const height = PADDING_Y + (layers.length - 1) * LAYER_GAP + PADDING_Y;

  // Compute edges
  const edges: LayoutEdge[] = [];
  for (const node of graph) {
    const toLayout = nodes.find((n) => n.role === node.role);
    if (!toLayout) continue;
    for (const dep of node.runAfter) {
      const fromLayout = nodes.find((n) => n.role === dep);
      if (fromLayout) edges.push({ from: fromLayout, to: toLayout });
    }
  }

  return { nodes, edges, width: Math.max(maxX, 400), height };
}

// ΓöÇΓöÇΓöÇ Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface WorkflowGraphProps {
  activeAgent: AgentRole | null;
  activeAgents?: AgentRole[];
  activeDomains?: Domain[];
  cycle: number;
  status: PipelineStatus;
  completedAgents?: AgentRole[];
  agentGraph?: AgentGraphNode[];
  onAgentClick?: (role: AgentRole) => void;
  selectedAgent?: AgentRole | null;
}

export function WorkflowGraph({
  activeAgent,
  activeAgents = [],
  activeDomains = [],
  cycle,
  status,
  completedAgents = [],
  agentGraph,
  onAgentClick,
  selectedAgent,
}: WorkflowGraphProps) {
  const isRunning = status === PIPELINE_STATUSES.RUNNING;
  const completedSet = useMemo(() => new Set(completedAgents), [completedAgents]);
  const activeSet = useMemo(
    () => new Set(activeAgents.length > 0 ? activeAgents : activeAgent ? [activeAgent] : []),
    [activeAgents, activeAgent],
  );
  const activeDomainSet = useMemo(() => new Set(activeDomains), [activeDomains]);

  const graph = useMemo(
    () => agentGraph?.length ? agentGraph.filter((n) => n.enabled) : DEFAULT_AGENT_GRAPH,
    [agentGraph],
  );
  const { nodes, edges, width, height } = useMemo(() => computeLayout(graph), [graph]);

  const handleNodeClick = useCallback(
    (role: AgentRole) => { onAgentClick?.(role); },
    [onAgentClick],
  );

  // Find exit (UX) and explorer nodes for cycle arcs
  const exitNode = nodes.find((n) => n.nodeType === GRAPH_NODE_TYPES.EXIT);
  const explorerNode = nodes.find((n) => n.role === AGENT_ROLES.EXPLORER);
  const hasLoop = !!(exitNode && explorerNode);

  // Two separate side arcs instead of one wrap-around
  const rightmostX = nodes.length > 0 ? Math.max(...nodes.map((n) => n.x)) : width;
  const leftmostX = nodes.length > 0 ? Math.min(...nodes.map((n) => n.x)) : 0;
  const arcRight = rightmostX + NODE_RADIUS + LOOP_MARGIN;
  const arcLeft = leftmostX - NODE_RADIUS - LOOP_MARGIN;

  // Right arc: Explorer ΓåÆ UX (clockwise, curves down the right side)
  const rightArcPath = hasLoop
    ? `M ${explorerNode!.x + NODE_RADIUS + 8} ${explorerNode!.y}
       C ${arcRight} ${explorerNode!.y},
         ${arcRight} ${exitNode!.y},
         ${exitNode!.x + NODE_RADIUS + 8} ${exitNode!.y}`
    : "";

  // Left arc: UX ΓåÆ Explorer (clockwise, curves up the left side)
  const leftArcPath = hasLoop
    ? `M ${exitNode!.x - NODE_RADIUS - 8} ${exitNode!.y}
       C ${arcLeft} ${exitNode!.y},
         ${arcLeft} ${explorerNode!.y},
         ${explorerNode!.x - NODE_RADIUS - 8} ${explorerNode!.y}`
    : "";

  const svgViewBox = hasLoop
    ? `${arcLeft - 15} 0 ${arcRight - arcLeft + 30} ${height}`
    : `0 0 ${width} ${height}`;

  // Collect unique domain columns for labels
  const domainColumns = useMemo(() => {
    const cols: { domain: Domain; x: number }[] = [];
    const seen = new Set<string>();
    for (const node of nodes) {
      if (node.domain && !seen.has(node.domain)) {
        seen.add(node.domain);
        cols.push({ domain: node.domain, x: node.x });
      }
    }
    return cols;
  }, [nodes]);

  return (
    <div
      className="flex h-full w-full items-center justify-center overflow-auto"
      style={{ background: "rgba(20, 21, 31, 0.5)" }}
    >
      <svg
        viewBox={svgViewBox}
        preserveAspectRatio="xMidYMid meet"
        className="h-full max-h-full w-full"
        style={{ minHeight: 300 }}
        aria-label="Agent pipeline workflow"
      >
        <defs>
          {nodes.map((node) => (
            <filter key={`glow-${node.role}`} id={`glow-${node.role}`} x="-100%" y="-100%" width="300%" height="300%">
              <feGaussianBlur stdDeviation="5" result="blur" />
              <feFlood floodColor={node.color} floodOpacity="0.5" result="color" />
              <feComposite in="color" in2="blur" operator="in" result="glow" />
              <feMerge>
                <feMergeNode in="glow" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          ))}
          {/* Right arc glow (violet) */}
          <filter id="glow-arc-right" x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="3" result="blur" />
            <feFlood floodColor={LOOP_COLOR_RIGHT} floodOpacity="0.25" result="color" />
            <feComposite in="color" in2="blur" operator="in" result="glow" />
            <feMerge>
              <feMergeNode in="glow" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
          {/* Left arc glow (indigo) */}
          <filter id="glow-arc-left" x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="3" result="blur" />
            <feFlood floodColor={LOOP_COLOR_LEFT} floodOpacity="0.25" result="color" />
            <feComposite in="color" in2="blur" operator="in" result="glow" />
            <feMerge>
              <feMergeNode in="glow" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
          {/* Arrowhead markers */}
          <marker id="arrow-right" viewBox="0 0 8 8" refX="8" refY="4"
            markerWidth="5" markerHeight="5" orient="auto">
            <path d="M 0 0 L 8 4 L 0 8 z" fill={LOOP_COLOR_RIGHT} fillOpacity="0.7" />
          </marker>
          <marker id="arrow-left" viewBox="0 0 8 8" refX="8" refY="4"
            markerWidth="5" markerHeight="5" orient="auto">
            <path d="M 0 0 L 8 4 L 0 8 z" fill={LOOP_COLOR_LEFT} fillOpacity="0.7" />
          </marker>
        </defs>

        {/* ΓöÇΓöÇ Cycle arcs (background layer, behind everything) ΓöÇΓöÇ */}

        {/* Right arc: Explorer ΓåÆ UX (violet, clockwise down) */}
        {hasLoop && (
          <>
            <path d={rightArcPath} fill="none" stroke={LOOP_COLOR_RIGHT} strokeOpacity={0.04} strokeWidth={1} />
            <motion.path
              d={rightArcPath}
              fill="none"
              stroke={LOOP_COLOR_RIGHT}
              strokeWidth={1.5}
              strokeLinecap="round"
              filter="url(#glow-arc-right)"
              markerEnd="url(#arrow-right)"
              initial={false}
              animate={{
                pathLength: isRunning ? 0.35 : 1,
                pathOffset: isRunning ? [0, 1] : 0,
                pathSpacing: isRunning ? 0.65 : 0,
                strokeOpacity: isRunning ? 0.55 : 0.1,
              }}
              transition={
                isRunning
                  ? {
                      pathOffset: { duration: 2.5, repeat: Infinity, ease: "linear" },
                      pathLength: { duration: 0.5 },
                      pathSpacing: { duration: 0.5 },
                      strokeOpacity: { duration: 0.5 },
                    }
                  : { duration: 0.5 }
              }
            />
          </>
        )}

        {/* Left arc: UX ΓåÆ Explorer (indigo, clockwise up) */}
        {hasLoop && (
          <>
            <path d={leftArcPath} fill="none" stroke={LOOP_COLOR_LEFT} strokeOpacity={0.04} strokeWidth={1} />
            <motion.path
              d={leftArcPath}
              fill="none"
              stroke={LOOP_COLOR_LEFT}
              strokeWidth={1.5}
              strokeLinecap="round"
              filter="url(#glow-arc-left)"
              markerEnd="url(#arrow-left)"
              initial={false}
              animate={{
                pathLength: isRunning ? 0.35 : 1,
                pathOffset: isRunning ? [0, 1] : 0,
                pathSpacing: isRunning ? 0.65 : 0,
                strokeOpacity: isRunning ? 0.55 : 0.1,
              }}
              transition={
                isRunning
                  ? {
                      pathOffset: { duration: 2.5, repeat: Infinity, ease: "linear" },
                      pathLength: { duration: 0.5 },
                      pathSpacing: { duration: 0.5 },
                      strokeOpacity: { duration: 0.5 },
                    }
                  : { duration: 0.5 }
              }
            />
          </>
        )}

        {/* ΓöÇΓöÇ Domain column labels ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        {domainColumns.map(({ domain, x }) => {
          const isDomainActive = activeDomainSet.size === 0 || activeDomainSet.has(domain);
          const domainColor = DOMAIN_COLORS[domain] ?? "rgba(255,255,255,0.4)";
          return (
            <text
              key={`domain-label-${domain}`}
              x={x}
              y={PADDING_Y + LAYER_GAP * 1.5}
              textAnchor="middle"
              fill={domainColor}
              opacity={isDomainActive ? 0.7 : 0.2}
              fontSize={8}
              fontFamily="var(--font-body)"
              letterSpacing="0.15em"
              fontWeight={600}
            >
              {DOMAIN_LABELS[domain]?.toUpperCase() ?? domain.toUpperCase()}
            </text>
          );
        })}

        {/* ΓöÇΓöÇ Edges ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        {edges.map(({ from, to }, i) => {
          const isActive = isRunning && activeSet.has(to.role);
          const isTraversed = completedSet.has(from.role) && (completedSet.has(to.role) || isActive);
          const isDomainEdge = to.domain != null;
          const isDomainActive = !isDomainEdge || activeDomainSet.size === 0 || activeDomainSet.has(to.domain!);

          const fromY = from.y + NODE_RADIUS + 4;
          const toY = to.y - NODE_RADIUS - 4;
          const dx = to.x - from.x;
          const dy = toY - fromY;
          const isStraight = Math.abs(dx) < 2;

          const pathD = isStraight
            ? `M ${from.x} ${fromY} L ${to.x} ${toY}`
            : `M ${from.x} ${fromY} C ${from.x} ${fromY + dy * 0.4}, ${to.x} ${toY - dy * 0.4}, ${to.x} ${toY}`;

          return (
            <g key={`edge-${i}`}>
              <path d={pathD} fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth={1} />
              <motion.path
                d={pathD}
                fill="none"
                stroke={
                  !isDomainActive ? "rgba(255,255,255,0.06)"
                    : isActive || isTraversed ? to.color
                    : "rgba(255,255,255,0.12)"
                }
                strokeWidth={isActive ? 2.5 : isTraversed ? 1.5 : 0.5}
                strokeDasharray={isActive ? "8 5" : "none"}
                strokeLinecap="round"
                initial={false}
                animate={{
                  strokeDashoffset: isActive ? [-26, 0] : 0,
                  strokeOpacity: !isDomainActive ? 0.06 : isActive ? 1 : isTraversed ? 0.4 : 0.1,
                }}
                transition={
                  isActive
                    ? { strokeDashoffset: { duration: 0.8, repeat: Infinity, ease: "linear" }, strokeOpacity: { duration: 0.3 } }
                    : { duration: 0.4 }
                }
              />
            </g>
          );
        })}

        {/* ΓöÇΓöÇ Cycle badge ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <AnimatePresence>
          {cycle > 0 && (
            <motion.g
              initial={{ opacity: 0, y: -4 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -4 }}
              transition={SPRING}
            >
              <rect x={width / 2 - 22} y={4} width={44} height={18} rx={9}
                fill="rgba(20, 21, 31, 0.8)" stroke="rgba(255,255,255,0.08)" strokeWidth={0.5} />
              <text x={width / 2} y={16} textAnchor="middle" fill="#94A3B8"
                fontSize={9} fontFamily="var(--font-code)">
                Cycle {cycle}
              </text>
            </motion.g>
          )}
        </AnimatePresence>

        {/* ΓöÇΓöÇ Nodes ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        {nodes.map((node) => {
          const isCurrent = activeSet.has(node.role) && isRunning;
          const isCompleted = completedSet.has(node.role) && !isCurrent;
          const isIdle = !isCurrent && !isCompleted;
          const isSelected = selectedAgent === node.role;
          const nodeDomain = getDomainFromRole(node.role);
          const isDomainActive = !nodeDomain || activeDomainSet.size === 0 || activeDomainSet.has(nodeDomain);
          const isDimmed = node.dynamicEnable && !isDomainActive;

          return (
            <g
              key={node.role}
              onClick={() => handleNodeClick(node.role)}
              style={{ cursor: onAgentClick ? "pointer" : "default" }}
              opacity={isDimmed ? 0.2 : 1}
            >
              {/* Native SVG tooltip */}
              <title>{`${node.label}\n${node.description}`}</title>

              {/* Breathing glow ring */}
              <AnimatePresence>
                {isCurrent && (
                  <motion.circle
                    key={`breathe-${node.role}`}
                    cx={node.x} cy={node.y} r={NODE_RADIUS + 8}
                    fill="none" stroke={node.color} strokeWidth={1.5}
                    initial={{ scale: 0.8, opacity: 0 }}
                    animate={{ scale: [1, 1.12, 1], opacity: [0.3, 0.6, 0.3] }}
                    exit={{ scale: 0.8, opacity: 0, transition: { duration: 0.4 } }}
                    transition={BREATHE_TRANSITION}
                    style={{ transformOrigin: `${node.x}px ${node.y}px` }}
                  />
                )}
              </AnimatePresence>

              {/* Selected ring */}
              {isSelected && (
                <circle cx={node.x} cy={node.y} r={NODE_RADIUS + 5}
                  fill="none" stroke={node.color} strokeWidth={2}
                  strokeDasharray={isDimmed ? "4 3" : "none"} opacity={0.8} />
              )}

              {/* Glass backdrop */}
              <motion.circle cx={node.x} cy={node.y} r={NODE_RADIUS}
                fill={isCurrent ? node.color : "rgba(20, 21, 31, 0.6)"}
                initial={false}
                animate={{
                  fillOpacity: isCurrent ? 0.2 : 1,
                  strokeWidth: isCurrent ? 2.5 : isCompleted ? 1.5 : 0.5,
                  strokeOpacity: isDimmed ? 0.06 : isCurrent ? 1 : isCompleted ? 0.4 : 0.08,
                }}
                stroke={
                  isDimmed ? "rgba(255,255,255,0.06)"
                    : isCurrent ? node.color
                    : isCompleted ? node.color
                    : "rgba(255,255,255,0.08)"
                }
                strokeDasharray={isDimmed ? "4 3" : "none"}
                transition={{ duration: 0.6, ease: "easeOut" }} />

              {/* Agent color fill ΓÇö only visible when active or completed */}
              <motion.circle cx={node.x} cy={node.y} r={NODE_RADIUS}
                fill={node.color}
                initial={false}
                animate={{
                  fillOpacity: isCurrent ? 0.25 : isCompleted ? 0.08 : 0,
                }}
                filter={isCurrent ? `url(#glow-${node.role})` : "none"}
                transition={{ duration: 0.6, ease: "easeOut" }} />

              {/* Icon ΓÇö always shows domain icon, colored when active/completed */}
              <g transform={`translate(${node.x - 8}, ${node.y - 8}) scale(0.667)`}>
                <motion.path
                  d={node.icon}
                  fill="none"
                  strokeWidth={1.5}
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  initial={false}
                  animate={{
                    stroke: isCurrent ? node.color : isCompleted ? node.color : "rgba(176,190,197,0.35)",
                    strokeOpacity: isCurrent ? 1 : isCompleted ? 0.7 : 0.35,
                  }}
                  transition={{ duration: 0.4 }}
                />
              </g>

              {/* Completion badge ΓÇö small check in bottom-right corner */}
              <AnimatePresence>
                {isCompleted && (
                  <motion.g
                    key={`check-${node.role}`}
                    initial={{ scale: 0, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    exit={{ scale: 0, opacity: 0 }}
                    transition={SPRING}
                  >
                    <circle cx={node.x + NODE_RADIUS - 3} cy={node.y + NODE_RADIUS - 3} r={6}
                      fill="rgba(20, 21, 31, 0.9)" stroke={node.color} strokeWidth={1} />
                    <path
                      d={`M ${node.x + NODE_RADIUS - 6} ${node.y + NODE_RADIUS - 3} l 2.5 2.5 L ${node.x + NODE_RADIUS} ${node.y + NODE_RADIUS - 6}`}
                      fill="none" stroke={node.color} strokeWidth={1.5}
                      strokeLinecap="round" strokeLinejoin="round" />
                  </motion.g>
                )}
              </AnimatePresence>

              {/* Label */}
              <text x={node.x} y={node.y + NODE_RADIUS + 13}
                textAnchor="middle"
                fill={node.color}
                opacity={isCurrent ? 1 : isCompleted ? 0.8 : isDimmed ? 0.15 : 0.6}
                fontSize={7} fontFamily="var(--font-body)"
                letterSpacing="0.1em" fontWeight={isCurrent ? 700 : isCompleted ? 600 : 400}>
                {node.label.toUpperCase()}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}

import fs from "node:fs";
import path from "node:path";
import { getClient } from "@/lib/copilot/client";
import { agentTools } from "@/lib/copilot/tools";
import { dequeue, isEmpty } from "@/lib/pipeline/steering";
import { getSkillDirectoriesForAgent } from "@/lib/pipeline/skill-manager";
import { getMcpServersForAgent } from "@/lib/pipeline/mcp-manager";
import { getCheatSheet } from "@/lib/pipeline/cheat-sheet-store";
import { projectScreenshotsDir } from "@/lib/pipeline/project-resolver";
import { startToolSpan, endSpanOk } from "@/lib/otel/spans";
import { recordToolInvocation } from "@/lib/otel/metrics";
import type { AgentRole, PipelineConfig } from "@/lib/types";
import { AGENT_ROLES, isAnalystRole, isFixerRole } from "@/lib/types";
import { approveAll } from "@github/copilot-sdk";
import type { SessionConfig } from "@github/copilot-sdk";

// ΓöÇΓöÇΓöÇ System prompt loader ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const PROMPTS_DIR = path.join(process.cwd(), "src", "lib", "copilot", "prompts");
const AGENTS_DIR = path.join(process.cwd(), "src", "lib", "copilot", "agents");
// Keep legacy path for backward compatibility during migration
const LEGACY_INSTRUCTIONS_DIR = path.join(
  process.cwd(),
  "src",
  "lib",
  "copilot",
  "instructions"
);

function loadPromptFile(dir: string, filename: string): string {
  const fp = path.join(dir, filename);
  if (fs.existsSync(fp)) return fs.readFileSync(fp, "utf-8");
  return "";
}

function loadSystemPrompt(role: AgentRole, config: PipelineConfig): string {
  // Load shared base from prompts/
  const basePrompt = loadPromptFile(PROMPTS_DIR, "_base.md");

  // Load agent-specific prompt from agents/, fall back to legacy instructions/
  let agentPrompt = loadPromptFile(AGENTS_DIR, `${role}.md`);
  if (!agentPrompt) {
    agentPrompt = loadPromptFile(LEGACY_INSTRUCTIONS_DIR, `${role}.md`);
  }

  const context = [
    "",
    "## PROJECT CONTEXT",
    "",
    `**Target project path:** ${config.projectPath}`,
    `**Target app URL:** ${config.appUrl}`,
    `**Inspiration:** "${config.inspiration}"`,
    `**Current model:** ${config.model}`,
    "",
    "## CRITICAL ΓÇö URL TARGETING RULES",
    "",
    `You are reviewing the application at **${config.appUrl}** ΓÇö this is the ONLY URL you should navigate to in a browser.`,
    "",
    "**DO NOT** navigate to localhost:3000 unless that is the target app URL above.",
    "**DO NOT** interact with the Endstate Dashboard ΓÇö that is the orchestration tool managing you, not the app under review.",
    "**DO NOT** create, modify, or read files outside the target project path above.",
    `**DO** use \`${config.appUrl}\` for all browser navigation, health checks, and API testing.`,
    `**DO** use \`${config.projectPath}\` as the root for all filesystem operations.`,
    "",
    "If the target app URL is not responding, create a CRITICAL task and stop. Do NOT fall back to browsing other URLs.",
  ].join("\n");

  // Inject cheat sheet for all agents except the Researcher (who produces it)
  let cheatSheetSection = "";
  if (role !== AGENT_ROLES.RESEARCHER) {
    const cheatSheet = getCheatSheet(config.projectPath);
    if (cheatSheet) {
      cheatSheetSection = [
        "",
        "## RESEARCHER CHEAT SHEET",
        "",
        "The following project overview was produced by the Researcher agent. Use this as your primary reference instead of re-exploring the project from scratch.",
        "",
        cheatSheet,
      ].join("\n");
    }
  }

  return [basePrompt, agentPrompt, context, cheatSheetSection].filter(Boolean).join("\n\n---\n\n");
}

// ΓöÇΓöÇΓöÇ MCP server configs per role ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function mcpPlaywright(projectPath: string) {
  // Route screenshots to .projects/<slug>/screenshots/ so artifacts
  // land in the correct project folder instead of the Endstate cwd.
  const screenshotsDir = projectScreenshotsDir(projectPath);
  return {
    type: "local" as const,
    command: "npx",
    args: ["@playwright/mcp@latest", "--output-dir", screenshotsDir],
    cwd: projectPath,
    tools: ["*"],
  };
}

function mcpFilesystem(projectPath: string) {
  return {
    type: "local" as const,
    command: "npx",
    args: ["-y", "@modelcontextprotocol/server-filesystem", projectPath],
    cwd: projectPath,
    tools: ["*"],
  };
}

function mcpGithub(projectPath: string) {
  return {
    type: "local" as const,
    command: "npx",
    args: ["-y", "@modelcontextprotocol/server-github"],
    cwd: projectPath,
    tools: ["*"],
  };
}

function mcpServersForRole(
  role: AgentRole,
  projectPath: string
): Record<string, { type: "local"; command: string; args: string[]; cwd: string; tools: string[] }> {
  // Domain-scoped roles: analyst-* gets filesystem, fixer-* gets filesystem + github
  if (isAnalystRole(role)) {
    return { fs: mcpFilesystem(projectPath) };
  }
  if (isFixerRole(role)) {
    return { fs: mcpFilesystem(projectPath), github: mcpGithub(projectPath) };
  }

  // Base roles and special roles
  switch (role) {
    case AGENT_ROLES.RESEARCHER:
    case AGENT_ROLES.ANALYST:
      return { fs: mcpFilesystem(projectPath) };

    case AGENT_ROLES.EXPLORER:
    case AGENT_ROLES.UX_REVIEWER:
      return { fs: mcpFilesystem(projectPath), playwright: mcpPlaywright(projectPath) };

    case AGENT_ROLES.FIXER:
    case AGENT_ROLES.CODE_SIMPLIFIER:
      return { fs: mcpFilesystem(projectPath), github: mcpGithub(projectPath) };

    case AGENT_ROLES.CONSOLIDATOR:
      return { fs: mcpFilesystem(projectPath), github: mcpGithub(projectPath), playwright: mcpPlaywright(projectPath) };

    default:
      return { fs: mcpFilesystem(projectPath) };
  }
}

// ΓöÇΓöÇΓöÇ Tool overrides ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function buildToolLists(config: PipelineConfig): {
  excludedTools?: string[];
} {
  const overrides = config.toolOverrides;
  if (!overrides || overrides.length === 0) return {};

  const excluded = overrides.filter((t) => !t.enabled).map((t) => t.name);
  if (excluded.length === 0) return {};

  return { excludedTools: excluded };
}

// ΓöÇΓöÇΓöÇ Session hooks ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

// Track OTel spans across pre/post hooks without mutating hook inputs
const spanMap = new WeakMap<object, ReturnType<typeof startToolSpan>>();

function buildHooks(): NonNullable<SessionConfig["hooks"]> {
  return {
    onPreToolUse: async (input, _invocation) => {
      const span = startToolSpan(input.toolName, "");
      recordToolInvocation(input.toolName);
      spanMap.set(input, span);
      return { permissionDecision: "allow" as const };
    },
    onPostToolUse: async (input, _invocation) => {
      const span = spanMap.get(input);
      if (span) {
        endSpanOk(span);
        spanMap.delete(input);
      }
    },
    onUserPromptSubmitted: async (input, _invocation) => {
      if (isEmpty()) return { modifiedPrompt: input.prompt };
      const steering = dequeue();
      if (!steering) return { modifiedPrompt: input.prompt };
      return {
        modifiedPrompt: `${input.prompt}\n\n[DEVELOPER STEERING]: ${steering.message}`,
      };
    },
  };
}

